import { isCustomColorPalette } from '../../../../core/types/color-palette.js';
import { isColoredRangeArray } from '../../../../core/types/colored-range.js';
import { isValidColorPalette } from '../../../../core/utils/is-valid-color-palette.js';
import type { XYChartColorPalette } from '../../../types/xy-chart.js';

export function getValidColorPalette(
  colorPalette: XYChartColorPalette | undefined,
  fallbackColorPalette: XYChartColorPalette,
): XYChartColorPalette {
  return colorPalette &&
    (isColoredRangeArray(colorPalette) ||
      isCustomColorPalette(colorPalette) ||
      isValidColorPalette(colorPalette))
    ? colorPalette
    : fallbackColorPalette;
}
